// STEP 1 — PARSE PURSUE COMMAND
// Accepts input from WhatsApp router or direct POST
// Extracts opportunity title, optional note, entity hint
// Examples:
//   'Nova pursue FEMA preparedness grant'
//   'Scout pursue BGE utility inspection'
//   'Nova pursue SBIR MONK DHS — EAF co-applicant'
const fs = require('fs');
const raw = $input.first().json;
const body = raw.body || raw;

const rawTitle = String(body.title || body.opportunity || body.text || '').trim();
const source = String(body.source || 'manual').toLowerCase();
const kevinNote = String(body.note || body.kevin_note || '').trim();
const entityHint = String(body.entity || '').toUpperCase();
const beachheadHint = String(body.beachhead || '').toUpperCase();

// Load KAI_Context for context-aware entity resolution
let kaiContext = {};
try { kaiContext = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) {}

// Resolve entity from hint or title keywords
const resolveEntity = (title, hint) => {
  if (hint && ['FP','EAF','MONK','MULTI'].includes(hint)) return hint;
  const t = title.toLowerCase();
  if (t.includes('grant') || t.includes('workforce') || t.includes('nonprofit') || t.includes('earn') || t.includes('eaf') || t.includes('cako') || t.includes('fema preparedness') || t.includes('workforce')) return 'EAF';
  if (t.includes('sbir') || t.includes('monk') || t.includes('r&d') || t.includes('patent') || t.includes('licensing')) return 'MONK';
  if (t.includes('inspection') || t.includes('contract') || t.includes('consulting') || t.includes('bd') || t.includes('rfp') || t.includes('utility') || t.includes('bridge') || t.includes('dfr') || t.includes('police') || t.includes('medical supply')) return 'FP';
  return 'MULTI';
};

// Resolve opportunity type
const resolveType = (title) => {
  const t = title.toLowerCase();
  if (t.includes('sbir') || t.includes('sttr')) return 'sbir';
  if (t.includes('grant') || t.includes('fema') || t.includes('earn') || t.includes('workforce')) return 'grant';
  if (t.includes('contract') || t.includes('rfp') || t.includes('inspection') || t.includes('dfr')) return 'contract';
  if (t.includes('consulting') || t.includes('advisory') || t.includes('omb m-26')) return 'consulting';
  if (t.includes('licensing') || t.includes('oem') || t.includes('partnership')) return 'licensing';
  return 'contract';
};

const entity = resolveEntity(rawTitle, entityHint);
const opportunityType = resolveType(rawTitle);

// Determine downstream actions based on entity
const triggerJordan = true; // always — Jordan drafts for all
const triggerIris = entity === 'EAF' || entity === 'MULTI'; // Iris tracks grant deadlines
const triggerAtlas = entity === 'MONK'; // Atlas flags for technical prep

return [{ json: {
  title: rawTitle,
  source,
  kevinNote,
  entity,
  beachheadHint,
  opportunityType,
  triggerJordan,
  triggerIris,
  triggerAtlas,
  timestamp: new Date().toISOString(),
  founderName: (kaiContext.founder || {}).name || 'Kevin Alexander Smith',
  founderCredentials: ((kaiContext.founder || {}).credentials || []).join(', ')
}}];

// STEP 2 — WRITE TO PIPELINE TABLE
// Creates pipeline record in Supabase
// Status = pursuing immediately
const https = require('https');
const input = $input.first().json;
const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';

const record = {
  title: input.title,
  source: input.source,
  entity: input.entity,
  opportunity_type: input.opportunityType,
  beachhead: input.beachheadHint || null,
  status: 'pursuing',
  kevin_note: input.kevinNote || null,
  jordan_triggered: input.triggerJordan,
  iris_triggered: input.triggerIris,
  atlas_triggered: input.triggerAtlas
};

let pipelineId = null;
let writeStatus = 'failed';

try {
  const body = JSON.stringify(record);
  const result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: SUPABASE_URL, port: 443, path: '/rest/v1/pipeline', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Prefer': 'return=representation', 'Content-Length': Buffer.byteLength(body) }
    }, (res) => { let d=''; res.on('data',c=>d+=c); res.on('end',()=>resolve({status:res.statusCode,body:d})); });
    req.on('error',reject); req.write(body); req.end();
  });
  if (result.status === 201 || result.status === 200) {
    writeStatus = 'saved';
    try { pipelineId = JSON.parse(result.body)[0]?.id || null; } catch(e) {}
  } else {
    writeStatus = 'error_' + result.status + ': ' + result.body.substring(0,200);
  }
} catch(e) {
  writeStatus = 'error: ' + e.message;
}

return [{ json: { ...input, pipelineId, writeStatus }}];

// STEP 3 — FIRE DOWNSTREAM AGENTS
// Jordan always fires — entity determines what it drafts:
//   EAF → LOI / grant application
//   FP  → capability statement
//   MONK → SBIR narrative
//   MULTI → capability statement + LOI
// Iris fires for EAF/MULTI — adds deadline tracking
// Atlas fires for MONK — flags technical prep
const http = require('http');
const input = $input.first().json;

const fireWebhook = async (path, payload) => {
  const bodyStr = JSON.stringify(payload);
  const opts = { hostname: 'host.docker.internal', port: 5678, path, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } };
  return new Promise(r => { const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(bodyStr); req.end(); });
};

// Determine Jordan task based on entity
const jordanTask = {
  'EAF':   'loi',
  'FP':    'capability_statement',
  'MONK':  'sbir_narrative',
  'MULTI': 'capability_statement_and_loi'
}[input.entity] || 'capability_statement';

const jordanPayload = {
  trigger: 'pursue_command',
  pipeline_id: input.pipelineId,
  opportunity: input.title,
  entity: input.entity,
  opportunity_type: input.opportunityType,
  task: jordanTask,
  kevin_note: input.kevinNote || '',
  founder_credentials: input.founderCredentials
};

// Always fire Jordan
await fireWebhook('/webhook/grant-writer', jordanPayload);

// Fire Iris for grant/EAF deadlines
if (input.triggerIris) {
  await fireWebhook('/webhook/iris-monitor', {
    trigger: 'pursue_command',
    pipeline_id: input.pipelineId,
    opportunity: input.title,
    entity: input.entity,
    note: 'New pipeline item added: ' + input.title
  });
}

// Fire Atlas for MONK technical prep
if (input.triggerAtlas) {
  await fireWebhook('/webhook/atlas-architect', {
    command: 'Pipeline MONK prep',
    detail: input.title + ' — SBIR/R&D technical narrative needed',
    pipeline_id: input.pipelineId
  });
}

return [{ json: { ...input, jordanTask, agentsFired: ['Jordan', ...(input.triggerIris?['Iris']:[]), ...(input.triggerAtlas?['Atlas']:[])] }}];

// STEP 4 — CONFIRM TO KEVIN VIA WHATSAPP
const http = require('http');
const input = $input.first().json;

const entityLabel = { 'FP': 'For-Profit', 'EAF': 'Nonprofit', 'MONK': 'R&D/IP', 'MULTI': 'Multi-entity' }[input.entity] || input.entity;
const taskLabel = {
  'loi': 'LOI draft',
  'capability_statement': 'capability statement',
  'sbir_narrative': 'SBIR narrative',
  'capability_statement_and_loi': 'capability statement + LOI'
}[input.jordanTask] || 'draft';

const dbIcon = input.writeStatus === 'saved' ? '\u2705' : '\u26A0\uFE0F';
const agents = (input.agentsFired || []).join(' + ');

let msg = `Bot reply: PIPELINE CONFIRMED\n\n`;
msg += `Opportunity: ${input.title}\n`;
msg += `Entity: ${entityLabel} [${input.entity}]\n`;
msg += `Type: ${input.opportunityType}\n`;
if (input.kevinNote) msg += `Your note: ${input.kevinNote}\n`;
msg += `\nPipeline record: ${dbIcon} ${input.writeStatus}\n`;
msg += `Agents fired: ${agents}\n`;
msg += `Jordan drafting: ${taskLabel}\n`;
msg += `\nDraft ready ~45 seconds.\nCheck Dashboard pipeline tab for status.`;

const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: msg } });
const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
await new Promise(r => { const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(msgBody); req.end(); });

// Aidan callback
const cbBody = JSON.stringify({ agent: 'Nova', subagent: 'Pursue', opportunity: input.title, entity: input.entity, pipelineId: input.pipelineId, writeStatus: input.writeStatus, agentsFired: input.agentsFired, timestamp: new Date().toISOString() });
const cbOpts = { hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } };
const cbReq = http.request(cbOpts, res => { res.on('data',()=>{}); res.on('end',()=>{}); }); cbReq.on('error',()=>{}); cbReq.write(cbBody); cbReq.end();

return [{ json: { success: true, opportunity: input.title, entity: input.entity, pipelineId: input.pipelineId, agentsFired: input.agentsFired }}];
